/* ═══ Repack ═══ */
static inline void r19_pack(const double*sr,const double*si,double*dr,double*di,size_t K,size_t T)
{for(size_t b=0;b<K/T;b++) for(int n=0;n<19;n++) for(size_t j=0;j<T;j++){
    dr[b*19*T+n*T+j]=sr[n*K+b*T+j]; di[b*19*T+n*T+j]=si[n*K+b*T+j];}}

static inline void r19_unpack(const double*sr,const double*si,double*dr,double*di,size_t K,size_t T)
{for(size_t b=0;b<K/T;b++) for(int n=0;n<19;n++) for(size_t j=0;j<T;j++){
    dr[n*K+b*T+j]=sr[b*19*T+n*T+j]; di[n*K+b*T+j]=si[b*19*T+n*T+j];}}

